#pragma once
#include <vector>
#include <limits>

/* Return the largest sum of any contiguous subarray in the vector x.
   Example:
      input: [-2, 1, -3, 4, -1, 2, 1, -5, 4]
      output: 6
   O(n) implementation of Kadane's algorithm. */
int maximumSubarray(std::vector<int> const& x) {
    // Handle empty input
    if (x.empty()) return std::numeric_limits<int>::lowest();

    int best = std::numeric_limits<int>::lowest();
    int current = 0;

    for (int value : x) {
        current = std::max(value, current + value);
        best    = std::max(best, current);
    }

    return best;
}
