/*
 * Count the number of edges in a directed graph given by an NxN adjacency
 * matrix stored in row‑major order.  All entries are expected to be 0 or 1.
 *
 * The implementation uses OpenMP parallelisation and a reduction to
 * maximise throughput on an 8‑thread x86‑64 machine.
 */
int edgeCount(const std::vector<int> &A, size_t N) {
    int count = 0;
#pragma omp parallel for reduction(+:count)
    for (size_t i = 0; i < N; ++i) {
        const int *row = &A[i * N];
        for (size_t j = 0; j < N; ++j) {
            count += row[j]; // row[j] is either 0 or 1
        }
    }
    return count;
}
