 * library and GCC extensions, so it compiles with `-fopenmp`.
 */
inline void mapPowersOfTwo(std::vector<int> const& x, std::vector<bool> &mask) {
    const std::size_t n = x.size();
    if (mask.size() < n) mask.resize(n);

