06_fft_dft:
```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#if !defined(M_PI)
#  define M_PI 3.14159265358979323846
#endif

// Parallel, vectorised, O(N²) DFT
inline void dft(const std::vector<double> &x, std::vector<std::complex<double>> &output)
{
    const std::size_t N = x.size();
    output.resize(N);

    const double two_pi_over_N = 2.0 * M_PI / static_cast<double>(N);

#pragma omp parallel for schedule(static)
    for (std::ptrdiff_t k = 0; k < static_cast<std::ptrdiff_t>(N); ++k)
    {
        std::complex<double> sum(0.0, 0.0);

        // SIMD-friendly inner loop
        std::ptrdiff_t n = 0;
#ifdef __AVX2__
#pragma omp simd
#endif
        for (n = 0; n < static_cast<std::ptrdiff_t>(N); ++n)
        {
            const double angle = two_pi_over_N * static_cast<double>(n * k);
            const double cosp = std::cos(angle);
            const double sinp = std::sin(angle);
            sum += std::complex<double>(x[n] * cosp, -x[n] * sinp);
        }

        output[k] = sum;
    }
}
