19_graph_shortest_path:
```cpp
#pragma once
#include <vector>
#include <deque>
#include <limits>

/*
 * Return the length of the shortest path from source to dest in the undirected
 * graph described by the adjacency matrix A (row‑major order).  A is an N×N
 * matrix, N is known, the graph is guaranteed to be connected.
 */
int shortestPathLength(std::vector<int> const& A, size_t N,
                       int source, int dest) noexcept
{
    // Use signed char to save memory and keep the visited flag as a byte.
    std::vector<char> visited(N, 0);
    std::vector<int>  dist    (N, -1);

    std::deque<int> q;
    visited[source] = 1;
    dist[source]    = 0;
    q.push_back(source);

    while (!q.empty()) {
        int cur = q.front();
        q.pop_front();

        if (cur == dest)
            return dist[cur];

        int base = cur * static_cast<int>(N);
        for (int i = 0; i < static_cast<int>(N); ++i) {
            if (A[base + i] && !visited[i]) {
                visited[i] = 1;
                dist[i]    = dist[cur] + 1;
                q.push_back(i);
            }
        }
    }
    // Should never reach here because the graph is connected
    return std::numeric_limits<int>::max();
}
