```cpp
#pragma once
#include <array>
#include <vector>
#include <cstddef>
#include <omp.h>

/* Vector x contains values between 0 and 100, inclusive. Count the number of
   values in [0,10), [10, 20), [20, 30), ... and store the counts in `bins`.
   Example:
   input: [7, 32, 95, 12, 39, 32, 11, 71, 70, 66]
   output: [1, 2, 0, 3, 0, 0, 1, 2, 0, 1]
*/
inline void binsBy10Count(const std::vector<double> &x, std::array<std::size_t, 10> &bins)
{
    // Initialize destination array to zero
    bins.fill(0);

    // Number of available threads
    const int nthreads = omp_get_max_threads();

    // Allocate per‑thread temporary counters
    // Using std::aligned_storage to avoid dynamic allocation overhead
    struct ThreadBins {
        std::size_t counts[10];
    };
    std::vector<ThreadBins> temp(nthreads);

    // Parallel loop with per-thread reductions
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        ThreadBins &local = temp[tid];
        // zero local counters once per thread
        for (auto &v : local.counts) v = 0;

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < x.size(); ++i) {
            // `x[i]` is guaranteed to be in [0,100]
            std::size_t bin = static_cast<std::size_t>(x[i]) / 10;
            ++local.counts[bin];
        }
    }

    // Merge per‑thread counts into the output array
    for (int t = 0; t < nthreads; ++t) {
        const ThreadBins &local = temp[t];
        for (std::size_t b = 0; b < 10; ++b) {
            bins[b] += local.counts[b];
        }
    }
}
