#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    std::size_t row;
    std::size_t column;
    double value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
   and A is a sparse matrix stored in COO format.
   x and y are length N and A is M x N.
   Example:
   input: alpha=0.5 beta=1.0 A=[{0,1,3}, {1,0,-1}] x=[-4, 2] y=[-1,1]
   output: y=[2, 3]
 */
inline void spmv(double alpha,
                 const std::vector<COOElement> &A,
                 const std::vector<double> &x,
                 double beta,
                 std::vector<double> &y,
                 std::size_t M,
                 std::size_t N)
{
    // Multiply y by beta
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(y.size()); ++i)
        y[static_cast<std::size_t>(i)] *= beta;

    // Update y with the sparse matrix-vector product.
    // Use OpenMP to parallelise the outermost loop.
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t ii = 0; ii < static_cast<std::ptrdiff_t>(A.size()); ++ii)
    {
        const COOElement &e = A[static_cast<std::size_t>(ii)];
        if (e.row < M && e.column < N) {
            // Local copy of alpha to avoid repeated loads
            const double factor = alpha * e.value;
            // The atomic operation ensures correctness when multiple threads update
            // the same y[row] value.  The probability of write conflicts is low
            // for typical sparse matrices, but this keeps the result exact.
            #pragma omp atomic
            y[e.row] += factor * x[e.column];
        }
    }
}
