```cpp
#pragma once
#include <vector>
#include <array>
#include <cstddef>
#include <omp.h>

/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0‑255.
   Store the results in `bins`.
   Example:

   input:  image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...]
*/
inline void pixelCounts(std::vector<int> const& image, std::array<std::size_t, 256> &bins)
{
    /* clear bins once before parallel update */
    std::fill(bins.begin(), bins.end(), 0);

    /* local thread‑private bins to avoid atomic writes */
    const int nt = omp_get_max_threads();
    std::vector<std::array<std::size_t, 256>> local_bins(nt);
    for (auto& lb : local_bins)
        std::fill(lb.begin(), lb.end(), 0);

    /* ----------------------------------------------------------
       Parallel accumulation – each thread writes only to its
       private histogram.
       ---------------------------------------------------------- */
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::array<std::size_t, 256> &hist = local_bins[tid];

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < image.size(); ++i) {
            hist[static_cast<unsigned char>(image[i])] += 1;
        }
    }

    /* merge thread‑local histograms into the final result */
    for (int t = 0; t < nt; ++t)
        for (int val = 0; val < 256; ++val)
            bins[val] += local_bins[t][val];
}
```
This implementation uses:

* `omp_get_max_threads()` and a thread‐private vector of histograms to eliminate costly atomic operations.
* `schedule(static)` to give each thread an equal slice of the input for optimal cache locality.
* Fast `static_cast<unsigned char>` to index the 256 bins, which guarantees unsigned index conversion.
* Pre‑zeroing the output bins to avoid stale values.

The code keeps exactly the same semantics while achieving better parallel performance on modern x86‑64 processors.

30_scan_prefix_sum:
```cpp
#pragma once
#include <vector>
#include <cstdint>
#include <cstddef>
#include <omp.h>

using std::vector;
using std::int64_t;

/* Compute the inclusive prefix sum of the vector x into output.
 * The operation is performed in parallel using OpenMP and is
 * equivalent to std::inclusive_scan.
 */
inline void prefixSum(const vector<int64_t> &x, vector<int64_t> &output) {
    const std::size_t n = x.size();
    output.resize(n);
    if (n == 0) return;

    const std::size_t n_threads = omp_get_max_threads();
    const std::size_t block = (n + n_threads - 1) / n_threads;   // ceil

    vector<int64_t> block_incs(n_threads, 0);

    // 1. Local inclusive scans per block
    #pragma omp parallel for schedule(static, block)
    for (std::size_t b = 0; b < n_threads; ++b) {
        const std::size_t start = b * block;
        const std::size_t end   = std::min(start + block, n);
        if (start >= end) continue;

        int64_t sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            sum += x[i];
            output[i] = sum;
        }
        block_incs[b] = sum;
    }

    // 2. Prefix sum of block totals (serial is cheap with few blocks)
    int64_t acc = 0;
    for (std::size_t b = 0; b < n_threads; ++b) {
        const int64_t old = block_incs[b];
        block_incs[b] = acc;
        acc += old;
    }

    // 3. Add block offset to each element (parallel)
    #pragma omp parallel for schedule(static, block)
    for (std::size_t b = 0; b < n_threads; ++b) {
        const std::size_t start = b * block;
        const std::size_t end   = std::min(start + block, n);
        if (start >= end) continue;

        const int64_t offset = block_incs[b];
        for (std::size_t i = start; i < end; ++i)
            output[i] += offset;
    }
}
