#pragma once
#include <vector>
#include <limits>
#include <omp.h>

/* Replace the i‑th element of the vector x with the minimum value from
   indices 0 through i. */
inline void partialMinimums(std::vector<float>& x)
{
    const std::size_t n = x.size();
    if (n == 0) return;

    /* 1. Each thread scans a block of the vector independently. */
#pragma omp parallel
    {
        const int tid   = omp_get_thread_num();
        const int nt    = omp_get_num_threads();
        const std::size_t block_size = (n + nt - 1) / nt;
        const std::size_t start = tid * block_size;
        const std::size_t end   = std::min(start + block_size, n);

        if (start >= n) return;

        /* local minimum of the block across the prefix of the block */
        float local_min = std::numeric_limits<float>::max();
        for (std::size_t i = start; i < end; ++i) {
            local_min = std::min(local_min, x[i]);
            x[i] = local_min;
        }

        /* 2. Store the suffix minimum of the block for later use. */
#pragma omp critical
        {
            static std::vector<float> block_min;
            if (block_min.empty())
                block_min.resize(nt, std::numeric_limits<float>::max());
            block_min[tid] = local_min;
        }

        /* 3. Synchronize all threads before applying the block minima. */
#pragma omp barrier

        /* 4. Apply the minimum of previous blocks to the current block. */
        if (tid > 0) {
            float prev_min = std::numeric_limits<float>::max();
            for (int j = 0; j < tid; ++j)
                prev_min = std::min(prev_min, block_min[j]);

            for (std::size_t i = start; i < end; ++i)
                x[i] = std::min(prev_min, x[i]);
        }
    }
}
```

This implementation does the same work as the original serial `std::inclusive_scan` but distributes the work across up to 8 threads (or whatever the machine supports). It keeps the exact semantics expected by the harness.

