inline void countQuadrants(std::vector<Point> const& points,
                           std::array<std::size_t, 4>& bins) {
    // Zero the output array
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    const std::size_t n = points.size();

    // Use a static thread‑local buffer that is reused across calls
    // to reduce allocation overhead. Size is chosen as a multiple of 64
    // to avoid cache line sharing between threads.
    static const std::size_t cacheLine = 64;
    static thread_local std::array<std::size_t, 4> localBins{};

#pragma omp parallel
    {
        // Each thread obtains a private copy of the counters.
        std::size_t l0 = 0, l1 = 0, l2 = 0, l3 = 0;
        const std::size_t start = omp_get_thread_num() * 
            ((n + omp_get_num_threads() - 1) / omp_get_num_threads());
        const std::size_t end   = std::min(start + ((n + omp_get_num_threads() - 1) / omp_get_num_threads()), n);

        for (std::size_t i = start; i < end; ++i) {
            const auto& p = points[i];
            if (p.x >= 0) {
                if (p.y >= 0)
                    ++l0;
                else
                    ++l3;
            } else {
                if (p.y >= 0)
                    ++l1;
                else
                    ++l2;
            }
        }

        // Reduce the local counters into the global array
#pragma omp atomic
        bins[0] += l0;
#pragma omp atomic
        bins[1] += l1;
#pragma omp atomic
        bins[2] += l2;
#pragma omp atomic
        bins[3] += l3;
    }
}
