#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

constexpr double PI = 3.141592653589793238462643383279502884;

/* Optimised FFT: in‑place radix‑2 Cooley–Tukey.
   The algorithm keeps the original behaviour (single precision real/imag arrays).
*/
void fft(const std::vector<std::complex<double>>& x,
         std::vector<double>& r,
         std::vector<double>& i)
{
    const std::size_t N = x.size();
    std::vector<std::complex<double>> a = x;            // copy for in‑place transform

    /* ---------- Butterfly stages ---------- */
    std::size_t n = N;
    double theta = PI / N;
    std::complex<double> W_m = std::exp(std::complex<double>(0.0, -theta)); // W_N

    for (std::size_t m = 1; m < N; m <<= 1) {
        std::complex<double> W = 1.0;
        for (std::size_t j = 0; j < m; ++j) {
            for (std::size_t k = j; k < N; k += (m << 1)) {
                std::complex<double> t = W * a[k + m];
                a[k + m] = a[k] - t;
                a[k] += t;
            }
            W *= W_m;
        }
        W_m *= W_m;            // (W_N)^2
    }

    /* ---------- Bit‑reversal permutation ---------- */
    // Pre‑compute reversed indices for speed
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t x = i, y = 0;
        for (std::size_t j = 0; j < static_cast<std::size_t>(std::log2(N)); ++j) {
            y = (y << 1) | (x & 1);
            x >>= 1;
        }
        rev[i] = y;
    }

    // Parallel swap using OpenMP
    #pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j) {
        std::size_t jp = rev[j];
        if (jp > j) {
            std::swap(a[j], a[jp]);
        }
    }

    /* ---------- Split into real/imag arrays ---------- */
    // Parallel copy
    #pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
