struct COOElement {
    std::size_t row, column;
    double value;
};

void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double>& Y,
          std::size_t M,
          std::size_t K,
          std::size_t N) {
    Y.assign(M * N, 0.0);

    /* Build X‑by‑row index: for each possible row r (0..K-1)
       store all X elements with that row.  This turns a linear
       scan over X into a direct lookup for the matching column
       of A. */
    std::vector<std::vector<COOElement>> X_by_row(K);
    for (auto const& e : X) {
        if (e.row < K)           // safety check – input should be valid
            X_by_row[e.row].push_back(e);
    }

    /* Parallel over A. Each thread may update the same entry in Y,
       so we use an atomic add for the double value.  On x86‑64 the
       implementation is efficient: the AMD Bulldozer‑like
       instruction set handles 64‑bit atomic adds as a single
       instruction.  The contention is limited because different
       rows of A are unlikely to hit the same Y element often. */
#pragma omp parallel for schedule(dynamic)
    for (std::intptr_t ai = 0; ai < static_cast<std::intptr_t>(A.size()); ++ai) {
        auto const& a = A[static_cast<std::size_t>(ai)];
        if (a.column >= K) continue;                // safety check
        for (auto const& x : X_by_row[static_cast<std::size_t>(a.column)]) {
            std::size_t idx = a.row * N + x.column;
#pragma omp atomic
            Y[idx] += a.value * x.value;
        }
    }
}
