/*
 * Computes the size of the largest connected component in an
 * undirected graph whose adjacency matrix is given in row-major
 * order as a flat vector `A` of length N*N.
 *
 * The implementation uses an iterative depth‑first search
 * with a manually managed stack and a compact `uint8_t`
 * array for visitation flags.  This avoids recursion overhead
 * and machine‑level cache misses while keeping the algorithm
 * linear in the number of edges (O(N²) for a dense matrix).
 */
int largestComponent(std::vector<int> const& A, size_t N)
{
    // visited[i] == 1  -> vertex i already processed
    std::vector<std::uint8_t> visited(N, 0);
    int maxSize = 0;

    // A compact stack
    std::vector<int> stack;
    stack.reserve(N);

    for (int start = 0; start < static_cast<int>(N); ++start)
    {
        if (visited[start]) continue;

        // Begin a new component
        int compSize = 0;
        stack.clear();
        stack.push_back(start);
        visited[start] = 1;

        while (!stack.empty())
        {
            int v = stack.back();
            stack.pop_back();
            ++compSize;

            int const* row = &A[v * N];
            for (int w = 0; w < static_cast<int>(N); ++w)
            {
                if (row[w] && !visited[w])
                {
                    visited[w] = 1;
                    stack.push_back(w);
                }
            }
        }
        maxSize = std::max(maxSize, compSize);
    }
    return maxSize;
}
