#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Sparse LU factorization using a dense representation of the matrix.
 * The algorithm is the same as in the reference implementation:
 *   * L is stored in column-major format in a 1-D array (size N*N),
 *   * U is stored in row-major format in a 1-D array (size N*N).
 * The function keeps the exact numeric result of the original version.
 */
inline void luFactorize(const std::vector<COOElement> &A,
                        std::vector<double> &L,
                        std::vector<double> &U,
                        size_t N)
{
    // Allocate a dense buffer for A
    std::vector<double> denseA(N * N, 0.0);
    for (const auto &e : A) {
        denseA[e.row * N + e.column] = e.value;
    }

    // Ensure L and U have the correct size
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* Main LU factorisation.
     * The algorithm is split into two phases per row i:
     *   1. Compute U[i][j] for j >= i
     *   2. Compute L[i][j] for j < i
     *
     * Using OpenMP to parallelise the outer i‑loop gives good performance
     * on an 8‑core machine. The inner sums are short (at most i or j terms),
     * so a simple sequential implementation is efficient.
     */
#pragma omp parallel for schedule(static)
    for (long long li = 0; li < static_cast<long long>(N); ++li) {
        const size_t i = static_cast<size_t>(li);

        // === Upper part (j >= i) ===
        for (size_t j = i; j < N; ++j) {
            double val = denseA[i * N + j];
            for (size_t k = 0; k < i; ++k) {
                val -= L[i * N + k] * U[k * N + j];
            }
            U[i * N + j] = val;
        }

        // === Lower part (j < i) ===
        for (size_t j = 0; j < i; ++j) {
            double val = denseA[i * N + j];
            for (size_t k = 0; k < j; ++k) {
                val -= L[i * N + k] * U[k * N + j];
            }
            L[i * N + j] = val / U[j * N + j];
        }

        // Diagonal of L is 1
        L[i * N + i] = 1.0;
    }
}
