inline void cellsXOR(std::vector<int> const& input, std::vector<int>& output, size_t N) {
    // Ensure output size matches input
    if (output.size() != input.size()) output.resize(input.size());

    const int* in  = input.data();
    int* out       = output.data();
    const size_t stride = N;

#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t base = i * stride;
        const size_t next = base + stride;
        const size_t prev = (i == 0) ? size_t(-1) : base - stride;
        for (size_t j = 0; j < N; ++j) {
            int count = 0;
            // north
            if (i > 0 && in[prev + j] == 1) ++count;
            // south
            if (i + 1 < N && in[next + j] == 1) ++count;
            // west
            if (j > 0 && in[base + j - 1] == 1) ++count;
            // east
            if (j + 1 < N && in[base + j + 1] == 1) ++count;
            out[base + j] = (count == 1) ? 1 : 0;
        }
    }
}
