#include <cstdint>
#include <omp.h>

/*
    Compute the prefix sum array of the vector x and return its sum.
    Example:
        input: [-7, 2, 1, 9, 4, 8]
        output: 15
*/
int64_t sumOfPrefixSum(const std::vector<int64_t> &x) {
    const std::size_t n = x.size();
    if (n == 0) return 0;

    std::vector<int64_t> prefixSum(n);

    /* --------------------------------------------------------------------
       1. Parallel inclusive scan (prefix sum) using the standard two‑pass
          algorithm that requires only integer addition – no atomics.
       -------------------------------------------------------------------- */
    const int nthr = omp_get_max_threads();

    // Temporary array to hold per‑thread partial sums
    std::vector<int64_t> threadSum(nthr, 0);

    /*  First pass: each thread scans its own chunk
       and records the local total into threadSum.               */
    #pragma omp parallel
    {
        const int tid   = omp_get_thread_num();
        const int nthr  = omp_get_num_threads();
        const std::size_t chunk = (n + nthr - 1) / nthr;      // ceil division
        const std::size_t start = tid * chunk;
        const std::size_t end   = std::min(start + chunk, n);

        int64_t sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            sum += x[i];
            prefixSum[i] = sum;
        }
        threadSum[tid] = sum;
    }

    /*  Second pass: add the offset from previous threads to each
        thread's chunk.                                                     */
    int64_t offset = 0;
    for (int tid = 0; tid < nthr; ++tid) {
        const std::size_t chunk = (n + nthr - 1) / nthr;
        const std::size_t start = tid * chunk;
        const std::size_t end   = std::min(start + chunk, n);
        if (start >= n) break;

        if (tid > 0) offset += threadSum[tid - 1];

        if (offset != 0) {
            for (std::size_t i = start; i < end; ++i) {
                prefixSum[i] += offset;
            }
        }
    }

    /* --------------------------------------------------------------------
       2. Sum the prefixSum array.  This can also be parallelised, but
          the overhead of dividing the work is typically negligible
          compared to the cost of the scan.  Still, we use a parallel
          reduction for completeness.
       -------------------------------------------------------------------- */
    int64_t total = 0;
    #pragma omp parallel for reduction(+:total)
    for (std::size_t i = 0; i < n; ++i) {
        total += prefixSum[i];
    }

    return total;
}
