#define M_PI 3.14159265358979323846
#endif

/* 
   Optimised Cooley‑Tukey radix‑2 FFT.
   The function has the same behaviour as the original one but uses
   pre‑computed twiddle factors, an in‑place iterative butterfly,
   bit‑reversal permutation written as a single loop and OpenMP
   parallelisation of the outer butterfly stages.
*/
void fft(std::vector<std::complex<double>> const& x,
         std::vector<std::complex<double>> &output) {
    const std::size_t N = x.size();
    output = x;                       // work in place

    // ---- pre‑compute twiddle factors ------------------------------------
    std::vector<std::complex<double>> twiddles(N / 2);
    const double ang = -2.0 * M_PI / N;
    for (std::size_t i = 0; i < N / 2; ++i) {
        twiddles[i] = std::complex<double>(std::cos(ang * i), std::sin(ang * i));
    }

    // ---- in‑place iterative radix‑2 FFT ---------------------------------
    std::size_t step = 2;
    for (std::size_t m = 1; m < N; m <<= 1) {
        const std::size_t half = m;
        const std::size_t twiddle_step = N / step;
#pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < half; ++k) {
            const std::complex<double> w = twiddles[k * twiddle_step];
            std::size_t offset = k << 1;
            for (std::size_t j = offset; j < N; j += step) {
                const std::size_t idx = j + half;
                std::complex<double> temp = output[idx] * w;
                output[idx] = output[j] - temp;
                output[j] = output[j] + temp;
            }
        }
        step <<= 1;
    }

    // ---- bit‑reversal permutation ---------------------------------------
    std::size_t rev = 0;
    for (std::size_t i = 0; i < N; ++i) {
        if (i < rev) {
            std::swap(output[i], output[rev]);
        }
        std::size_t mask = N >> 1;
        while (mask <= rev) {
            rev ^= mask;
            mask >>= 1;
        }
        rev ^= mask;
    }
}
