struct Point
{
    double x, y;
};

// Inline area computation – no extra function call overhead.
inline double triArea(const Point& a, const Point& b, const Point& c) noexcept
{
    // 0.5 * |cross product|
    return 0.5 * std::fabs(
        a.x * (b.y - c.y) +
        b.x * (c.y - a.y) +
        c.x * (a.y - b.y));
}

/* Return the area of the smallest triangle that can be formed by any 3 points.
   Example:
   input: [{0, 10}, {5, 5}, {1,0}, {-1, 1}, {-10, 0}]
   output: 5.5
*/
inline double smallestArea(const std::vector<Point>& points) noexcept
{
    const std::size_t n = points.size();

    if (n < 3)
        return 0.0;

    double minArea = std::numeric_limits<double>::max();

    // Parallelize the outer two loops; the innermost loop stays sequential.
    // We use omp reduction to compute the overall minimum safely.
    #pragma omp parallel for collapse(2) reduction(min:minArea) schedule(static)
    for (std::size_t i = 0; i < n - 2; ++i)
    {
        for (std::size_t j = i + 1; j < n - 1; ++j)
        {
            for (std::size_t k = j + 1; k < n; ++k)
            {
                const double area = triArea(points[i], points[j], points[k]);

                // Only update the local minimum if the new area is strictly smaller.
                if (area < minArea)
                    minArea = area;
            }
        }
    }

    return minArea;
}
