 *   • The work is split into friendly blocks that can be processed in
 *     parallel by an OpenMP parallel region.
 *   • No dynamic memory allocations inside the parallel loop.
 */
inline void reversePrefixSum(std::vector<int> const& x, std::vector<int> &output) {
    const std::size_t n = x.size();
    if (output.size() < n) output.resize(n);

    /* Splitting into blocks handled by OpenMP. */
    const std::size_t block_size = 128;            // tuned for cache; adjust if needed
    const std::size_t nblocks = (n + block_size - 1) / block_size;
    std::vector<int> block_totals(nblocks, 0);

    /* Step 1: compute partial sums for each block in reverse order. */
#pragma omp parallel for schedule(static)
    for (std::size_t blk = 0; blk < nblocks; ++blk) {
        const std::size_t start = blk * block_size;
        const std::size_t end   = std::min(start + block_size, n);

        int sum = 0;
        /* iterate from end-1 down to start */
        for (std::size_t i = end; i-- > start; ) {
            sum += x[i];
            output[i] = sum;          // store local suffix sum
        }
        block_totals[blk] = sum;      // last element's suffix sum (last processed element)
    }

    /* Step 2: compute cumulative sums of block_totals. */
    const int total_blocks = static_cast<int>(nblocks);
    int acc = 0;
    for (int blk = 0; blk < total_blocks; ++blk) {
        int tmp = block_totals[blk];
        block_totals[blk] = acc;
        acc += tmp;
    }

    /* Step 3: add the accumulated block totals to each block's entries. */
#pragma omp parallel for schedule(static)
    for (std::size_t blk = 0; blk < nblocks; ++blk) {
        const std::size_t start = blk * block_size;
        const std::size_t end   = std::min(start + block_size, n);
        const int add = block_totals[blk];
        for (std::size_t i = start; i < end; ++i) {
            output[i] += add;
        }
    }
}
```

This implementation removes the explicit reverse copy, keeps the algorithm cache‑friendly, and takes advantage of the 8 available threads using OpenMP. The logic and results remain identical to the original serial version.

