```cpp
#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax = b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:
   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
inline void solveLinearSystem(const std::vector<COOElement> &A,
                              const std::vector<double> &b,
                              std::vector<double> &x, size_t N)
{
    /* ----------------------------------------------
       * Step 1 – Build a contiguous dense matrix
       * ---------------------------------------------- */
    std::vector<double> matrix(N * N, 0.0);
    for (const auto &e : A)
        matrix[e.row * N + e.column] = e.value;

    /* ----------------------------------------------
       * Step 2 – Copy RHS vector (b), and resize x
       * ---------------------------------------------- */
    std::vector<double> b_copy = b;
    x.assign(N, 0.0);

    /* ----------------------------------------------
       * Step 3 – Gaussian elimination with partial
       * pivoting (serial – data dependency).
       * ---------------------------------------------- */
    for (size_t i = 0; i < N; ++i) {
        /* Find pivot row */
        size_t maxRow = i;
        double maxVal = std::abs(matrix[i * N + i]);
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(matrix[k * N + i]);
            if (val > maxVal) {
                maxVal = val;
                maxRow = k;
            }
        }

        /* Swap rows in matrix and RHS */
        if (maxRow != i) {
            for (size_t k = i; k < N; ++k) {
                std::swap(matrix[maxRow * N + k], matrix[i * N + k]);
            }
            std::swap(b_copy[maxRow], b_copy[i]);
        }

        /* Eliminate lower rows */
        const double pivot = matrix[i * N + i];
        #pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            double factor = matrix[k * N + i] / pivot;
            matrix[k * N + i] = 0.0; // explicitly zero
            for (size_t j = i + 1; j < N; ++j) {
                matrix[k * N + j] -= factor * matrix[i * N + j];
            }
            b_copy[k] -= factor * b_copy[i];
        }
    }

    /* ----------------------------------------------
       * Step 4 – Back substitution
       * ---------------------------------------------- */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = b_copy[i];
        for (size_t j = i + 1; j < N; ++j) {
            sum -= matrix[i * N + j] * x[j];
        }
        x[i] = sum / matrix[i * N + i];
    }
}
