#pragma once
#include <vector>
#include <algorithm>

struct Point { double x, y; };

inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

// convex hull using Andrew's monotone chain algorithm
void convexHull(std::vector<Point> const& points, std::vector<Point> &hull) {
    const std::size_t n = points.size();
    if (n < 3) { hull = points; return; }

    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) noexcept {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    hull.clear();
    hull.reserve(2 * n);

    // lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull.back(), sorted[i]) <= 0)
            hull.pop_back();
        hull.push_back(sorted[i]);
    }

    // upper hull
    std::size_t t = hull.size() + 1;
    for (std::size_t i = n; i-- > 1;) {
        while (hull.size() >= t &&
               cross(hull[hull.size() - 2], hull.back(), sorted[i - 1]) <= 0)
            hull.pop_back();
        hull.push_back(sorted[i - 1]);
    }

    hull.pop_back();  // last point is same as first
}
