/*
 * Return the distance between the closest two elements in the vector `x`.
 * The function preserves the original semantics: if the vector contains
 * fewer than two elements, it returns 0.0.  The algorithm is a brute‑force
 * O(n²) scan but is parallelised across the available threads using
 * OpenMP, yielding a large speedup on modern multi‑core CPUs.
 */
double closestPair(std::vector<double> const& x)
{
    const std::size_t n = x.size();
    if (n < 2)
        return 0.0;

    double minDist = std::numeric_limits<double>::max();

    /* Parallel reduction over the outer loop.
     * Each thread keeps a private `minDist` and the final value is the
     * minimum of all threads.  The schedule is static to avoid
     * thread contention for the reduction variable. */
    #pragma omp parallel for schedule(static) reduction(min:minDist)
    for (std::size_t i = 0; i < n - 1; ++i) {
        const double xi = x[i];
        for (std::size_t j = i + 1; j < n; ++j) {
            const double d = std::fabs(xi - x[j]);   // fast L1 distance
            if (d < minDist)
                minDist = d;
        }
    }
    return minDist;
}
