```cpp
#pragma once
#include <vector>
#include <omp.h>

/* 5‑point 2‑D Jacobi stencil
 *   output[i,j] = (input[i-1,j] + input[i+1,j] + input[i,j-1] +
 *                  input[i,j+1] + input[i,j]) / 5.0
 *   Outside the image border the contribution is treated as zero.
 *
 *  The implementation below is fully parallelized with OpenMP,
 *  blocked for cache friendliness, uses pointer arithmetic
 *  for speed, and exploits the fact that division by five
 *  can be replaced with a multiply by its reciprocal.
 */
inline void jacobi2D(std::vector<double> const &input,
                     std::vector<double> &output, size_t N)
{
    constexpr double r5 = 0.2;                // 1/5
    const size_t stride = N;
    const size_t block  = 64;                 // cache block size (tunable)

    // Parallelize outer loop by rows, each thread works on a contiguous block
    #pragma omp parallel for schedule(static)
    for (size_t bi = 0; bi < N; bi += block) {
        size_t i_max = std::min(bi + block, N);
        for (size_t i = bi; i < i_max; ++i) {
            const double *row       = &input[i * stride];
            double *      out_row   = &output[i * stride];
            const double *row_above = (i > 0)    ? &input[(i - 1) * stride] : nullptr;
            const double *row_below = (i < N-1)  ? &input[(i + 1) * stride] : nullptr;

            for (size_t j = 0; j < N; ++j) {
                double sum = row[j];                      // center
                if (row_above)   sum += row_above[j];     // north
                if (row_below)   sum += row_below[j];     // south
                if (j > 0)       sum += row[j - 1];       // west
                if (j < N-1)     sum += row[j + 1];       // east
                out_row[j] = sum * r5;
            }
        }
    }
}
