/* Find the k‑th smallest element of the vector `x`.
   `k` is 1‑based (k = 1 returns the minimum value).
   The function preserves the original vector and runs in
   expected O(n) time. */
int findKthSmallest(std::vector<int> const& x, int k) {
    // Copy the input so we don't modify it.
    std::vector<int> tmp = x;
    // nth_element places the element that would be at position k-1
    // (zero‑based) into that position, guaranteeing that all
    // elements before it are <= it and all elements after it are >= it.
    std::nth_element(tmp.begin(), tmp.begin() + (k - 1), tmp.end());
    return tmp[k - 1];
}
