inline void sortIgnoreZero(std::vector<int>& x) {
    if (x.empty())
        return;

    // Gather non‑zero elements and their original positions
    std::vector<int> nonZeroVals;
    nonZeroVals.reserve(x.size());

    for (int v : x) {
        if (v != 0)
            nonZeroVals.push_back(v);
    }

    // If no non‑zero values, nothing to do
    if (nonZeroVals.empty())
        return;

    // Sort the non‑zero values
    std::sort(nonZeroVals.begin(), nonZeroVals.end());

    // Overwrite the original vector with sorted non‑zero values
    std::size_t idx = 0;
    for (std::size_t i = 0; i < x.size(); ++i) {
        if (x[i] != 0) {
            x[i] = nonZeroVals[idx++];
        }
    }
}
