    if (x.empty())
        return std::size_t(-1);                                 // undefined behaviour in the original; keep same
    std::size_t best_idx = 0;
    double best_val = std::abs(x[0] - M_PI);

    #pragma omp parallel
    {
        std::size_t local_idx = best_idx;
        double local_min = best_val;
        #pragma omp for nowait
        for (std::size_t i = 1; i < x.size(); ++i)
        {
            double d = std::abs(x[i] - M_PI);
            if (d < local_min)
            {
                local_min = d;
                local_idx = i;
            }
        }
        #pragma omp critical
        {
            if (local_min < best_val)
            {
                best_val = local_min;
                best_idx = local_idx;
            }
        }
    }
    return best_idx;
}
