struct Point
{
    double x, y;
};

inline double dist_sq(const Point& a, const Point& b)
{
    double dx = b.x - a.x;
    double dy = b.y - a.y;
    return dx * dx + dy * dy;
}

inline double dist(const Point& a, const Point& b)
{
    return std::sqrt(dist_sq(a, b));
}

inline double cross(const Point& a, const Point& b, const Point& c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Return the perimeter of the smallest convex polygon that contains all the points in the vector points.
   Example:
   input: [{0, 3}, {1, 1}, {2, 2}, {4, 4}, {0, 0}, {1, 2}, {3, 1}, {3, 3}]
   output: 13.4477
*/
double convexHullPerimeter(const std::vector<Point>& points)
{
    constexpr size_t minHullSize = 3;
    if (points.size() < minHullSize)
        return 0.0;

    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b)
              {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    size_t n = pts.size();
    std::vector<Point> hull(2 * n);
    size_t k = 0;

    /* Build lower hull */
    for (size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], pts[i]) <= 0)
            --k;
        hull[k++] = pts[i];
    }

    /* Build upper hull */
    size_t t = k + 1;
    for (size_t i = n - 1; i-- > 0;)
    {
        while (k >= t && cross(hull[k - 2], hull[k - 1], pts[i]) <= 0)
            --k;
        hull[k++] = pts[i];
    }
    hull.resize(k - 1);

    double perimeter = 0.0;
#pragma omp parallel for reduction(+:perimeter)
    for (size_t i = 0; i < hull.size(); ++i)
    {
        size_t j = (i + 1) % hull.size();
        perimeter += std::sqrt(dist_sq(hull[i], hull[j]));
    }

    return perimeter;
}
