#include <algorithm>
#include <omp.h>

constexpr int edgeKernel[3][3] = {
    {-1, -1, -1},
    {-1,  8, -1},
    {-1, -1, -1}
};

/* Convolution implementation optimized for speed.
 *
 * 1. Parallelise the outer loops with OpenMP.
 * 2. Separate the interior pixels (no boundary checks) from image borders.
 * 3. Use pointer arithmetic to minimise index calculations.
 * 4. Keep the original behaviour (zero‑padding, clipping 0‑255).
 */
inline void convolveKernel(std::vector<int> const& imageIn,
                           std::vector<int> &imageOut, size_t N) noexcept
{
    // Padding size
    constexpr int kSize   = 3;
    constexpr int kHalf   = kSize / 2;

    // Helper lambda to clamp the result
    auto clamp = [](int v) -> int {
        return v < 0 ? 0 : (v > 255 ? 255 : v);
    };

    // Process interior region (no boundary checks)
    #pragma omp parallel for collapse(2)
    for (size_t i = kHalf; i < N - kHalf; ++i) {
        for (size_t j = kHalf; j < N - kHalf; ++j) {
            const int* base = &imageIn[i * N + j];
            int sum = 0;
            for (int ki = -kHalf; ki <= kHalf; ++ki) {
                const int* row = base + ki * N;
                for (int kj = -kHalf; kj <= kHalf; ++kj) {
                    sum += row[kj] * edgeKernel[ki + kHalf][kj + kHalf];
                }
            }
            imageOut[i * N + j] = clamp(sum);
        }
    }

    // Process border rows and columns (requires boundary handling)
    #pragma omp parallel for
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = 0; j < N; ++j) {
            // Skip cells already processed
            if (i >= kHalf && i < N - kHalf && j >= kHalf && j < N - kHalf)
                continue;

            int sum = 0;
            for (int ki = -kHalf; ki <= kHalf; ++ki) {
                int x = static_cast<int>(i) + ki;
                if (x < 0 || x >= static_cast<int>(N)) continue;
                const int* row = &imageIn[x * N];
                for (int kj = -kHalf; kj <= kHalf; ++kj) {
                    int y = static_cast<int>(j) + kj;
                    if (y < 0 || y >= static_cast<int>(N)) continue;
                    sum += row[y] * edgeKernel[ki + kHalf][kj + kHalf];
                }
            }
            imageOut[i * N + j] = clamp(sum);
        }
    }
}
