/*
 * Compute the rank of each element in x. The rank of element x[i] is its
 * position in the sorted version of x. Ties are broken consistently by
 * the original index order.
 */
inline void ranks(const std::vector<float> &x, std::vector<size_t> &ranks_) {
    const size_t n = x.size();
    ranks_.resize(n);

    // Store indices [0, 1, 2, …, n‑1] and sort them based on the values
    // in x.  The standard library's parallel sort is used for speed on
    // multi‑core systems.
    std::vector<size_t> indices(n);
    std::iota(indices.begin(), indices.end(), 0);
    std::sort(std::execution::par, indices.begin(), indices.end(),
              [&](size_t i1, size_t i2) { return x[i1] < x[i2]; });

    // Write the rank of each original element
    for (size_t rank = 0; rank < n; ++rank) {
        ranks_[indices[rank]] = rank;
    }
}
