    #pragma omp parallel for reduction(||:foundX)
    for (std::size_t i = 0; i < x.size(); ++i)
        if (x[i] == val) { foundX = true; break; }

    // Scan second vector in parallel
    #pragma omp parallel for reduction(||:foundY)
    for (std::size_t i = 0; i < y.size(); ++i)
        if (y[i] == val) { foundY = true; break; }

    return foundX ^ foundY;
}
