    {
        double d = std::numeric_limits<double>::max();
        for (size_t i = left; i <= right; ++i)
            for (size_t j = i + 1; j <= right; ++j)
                d = std::min(d, dist(points[i], points[j]));
        std::sort(points.begin() + left, points.begin() + right + 1,
                  [](const Point& a, const Point& b){ return a.y < b.y; });
        return d;
    }

    size_t mid = (left + right) / 2;
    double midx = points[mid].x;

    double d = std::min(closest_pair_rec(points, tmp, left, mid),
                        closest_pair_rec(points, tmp, mid + 1, right));

    /* merge the two halves by Y‑coordinate */
    std::merge(points.begin() + left, points.begin() + mid + 1,
               points.begin() + mid + 1, points.begin() + right + 1,
               tmp.begin(), [](const Point& a, const Point& b){ return a.y < b.y; });
    std::copy(tmp.begin(), tmp.begin() + (right - left + 1),
              points.begin() + left);

    /* build strip of points close to the division line */
    std::vector<Point> strip;
    strip.reserve(right - left + 1);
    for (size_t i = left; i <= right; ++i)
        if (std::abs(points[i].x - midx) < d)
            strip.push_back(points[i]);

    /* compare each point with next at most 7 points ahead */
    for (size_t i = 0; i < strip.size(); ++i)
        for (size_t j = i + 1;
             j < strip.size() && (strip[j].y - strip[i].y) < d; ++j)
            d = std::min(d, dist(strip[i], strip[j]));

    return d;
}

} // anonymous namespace

inline double closestPair(std::vector<Point> const& input) {
    if (input.size() < 2)   return 0.0;

    std::vector<Point> points = input;               // make a copy to sort
    std::sort(points.begin(), points.end(),
              [](const Point& a, const Point& b){ return a.x < b.x; });

    std::vector<Point> tmp(points.size());

    return closest_pair_rec(points, tmp, 0, points.size() - 1);
}
