#pragma once
#include <cmath>
#include <vector>
#include <complex>
#include <algorithm>
#include <cstdint>

#if !defined(M_PI)
# define M_PI 3.14159265358979323846
#endif

// ------------------------------------------------------------
// Optimised radix‑2 in‑place FFT implementation (forward direction)
// ------------------------------------------------------------
static inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    std::size_t k = N;
    const double thetaT = 3.14159265358979323846264338328L / N;
    std::complex<double> phiT = std::polar(1.0, -thetaT);   // e^(-i*2π/N)

    // Iterative decimation‑in‑time
    while (k > 1)
    {
        const std::size_t n = k;
        k >>= 1;
        phiT *= phiT;                         // e^(-i*2π/k)
        std::complex<double> T = 1.0;

        // Each inner loop over `l` is independent -> safe to parallelise
        #pragma omp parallel for schedule(static)
        for (std::size_t l = 0; l < k; ++l)
        {
            std::complex<double> tT = T;     // local copy of the twiddle factor
            for (std::size_t a = l; a < N; a += n)
            {
                const std::size_t b = a + k;
                const std::complex<double> t  = x[a] - x[b];
                x[a] += x[b];
                x[b] = t * tT;
            }
            T = tT * phiT;
        }
    }

    // Bit‑reversal permutation (in-place)
    const unsigned int m = static_cast<unsigned int>(std::log2(N));
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t j = i;
        j = ((j & 0xaaaaaaaaU) >> 1) | ((j & 0x55555555U) << 1);
        j = ((j & 0xccccccccU) >> 2) | ((j & 0x33333333U) << 2);
        j = ((j & 0xf0f0f0f0U) >> 4) | ((j & 0x0f0f0f0fU) << 4);
        j = ((j & 0xff00ff00U) >> 8) | ((j & 0x00ff00ffU) << 8);
        j = (j >> 16) | (j << 16);
        j >>= (32 - m);
        if (j > i)
            std::swap(x[i], x[j]);
    }
}

// ------------------------------------------------------------
// Inverse FFT (in-place)
// ------------------------------------------------------------
inline void ifft(std::vector<std::complex<double>>& x)
{
    // Conjugate -> forward FFT -> conjugate again
    for (auto& v : x) v = std::conj(v);
    fft_helper(x);
    for (auto& v : x) v = std::conj(v);

    // Normalise
    const double invN = 1.0 / static_cast<double>(x.size());
    for (auto& v : x) v *= invN;
}
