inline void gemm(const std::vector<double>& A,
                 const std::vector<double>& B,
                 std::vector<double>& C,
                 size_t M, size_t K, size_t N)
{
    // Convert to raw pointers for speed
    const double* a = A.data();
    const double* b = B.data();
    double* c = C.data();

    // Block sizes tuned for x86‑64 cache hierarchy.
    constexpr size_t BM = 32;   // block size for rows of A / C
    constexpr size_t BK = 32;   // block size for columns of A / rows of B
    constexpr size_t BN = 32;   // block size for columns of B / C

    // Parallelise over blocks of rows
    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += BM) {
        size_t i_lim = std::min(ii + BM, M);
        for (size_t kk = 0; kk < K; kk += BK) {
            size_t k_lim = std::min(kk + BK, K);
            for (size_t jj = 0; jj < N; jj += BN) {
                size_t j_lim = std::min(jj + BN, N);

                // Unroll inner loops
                for (size_t i = ii; i < i_lim; ++i) {
                    double* c_row = c + i * N + jj;
                    const double* a_row = a + i * K + kk;
                    for (size_t k = kk; k < k_lim; ++k) {
                        double a_val = a_row[k - kk];
                        const double* b_row = b + k * N + jj;
                        // further unroll over j
                        size_t j = 0;
                        for (; j + 7 < j_lim - jj; j += 8) {
                            c_row[j] += a_val * b_row[j];
                            c_row[j+1] += a_val * b_row[j+1];
                            c_row[j+2] += a_val * b_row[j+2];
                            c_row[j+3] += a_val * b_row[j+3];
                            c_row[j+4] += a_val * b_row[j+4];
                            c_row[j+5] += a_val * b_row[j+5];
                            c_row[j+6] += a_val * b_row[j+6];
                            c_row[j+7] += a_val * b_row[j+7];
                        }
                        for (; j < j_lim - jj; ++j) {
                            c_row[j] += a_val * b_row[j];
                        }
                    }
                }
            }
        }
    }
}
