#pragma once
#include <vector>
#include <cstddef>
#include <cmath>
#include <omp.h>

/* Simulates one generation of Conway's Game of Life.
 * The function reads the state from `input` (row‑major NxN grid)
 * and writes the next state into `output`.  Both buffers are
 * of size N*N and contain 0 (dead) or 1 (alive).  The algorithm
 * follows the classic rules of the Game of Life.
 */
inline void gameOfLife(const std::vector<int>& input,
                       std::vector<int>& output,
                       size_t N)
{
    // Ensure buffers have the right size
    const size_t sz = N * N;
    if (input.size() != sz || output.size() != sz) return;

    // Use raw pointers for fastest access
    const int*  in = input.data();
    int*        out = output.data();

    // Parallelise the outer loop; each iteration is independent.
    #pragma omp parallel for schedule(static, 256)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t iN   = i * N;
        const size_t im1N = (i > 0)   ? (i-1) * N : 0;
        const size_t ip1N = (i < N-1) ? (i+1) * N : 0;
        for (size_t j = 0; j < N; ++j, ++iN, ++im1N, ++ip1N)
        {
            // Count live neighbours
            int sum = 0;

            // Vertical neighbours
            if (i > 0)     sum += in[im1N + j];
            if (i < N-1)   sum += in[ip1N + j];

            // Horizontal neighbours
            if (j > 0)     sum += in[iN + j - 1];
            if (j < N-1)   sum += in[iN + j + 1];

            // Diagonals
            if (i > 0 && j > 0)         sum += in[im1N + j - 1];
            if (i > 0 && j < N-1)       sum += in[im1N + j + 1];
            if (i < N-1 && j > 0)       sum += in[ip1N + j - 1];
            if (i < N-1 && j < N-1)     sum += in[ip1N + j + 1];

            // Apply Game of Life rules
            const int cur = in[iN + j];
            out[iN + j] = (cur == 1)
                ? ((sum < 2 || sum > 3) ? 0 : 1)
                : (sum == 3 ? 1 : 0);
        }
    }
}
```
This version keeps exactly the same semantics while:

* Using raw pointer arithmetic for minimal indexing overhead.
* Eliminating repeated size multiplications inside loops.
* Parallelising the outer row‑loop with OpenMP.
* Using simple arithmetic for neighbour checks instead of many conditional branches.

