#pragma once
#include <vector>
#include <cstddef>
#include <x86intrin.h>   // for popcnt

/* Return the index of the first even number in the vector x.
   Examples:
   input: [7, 3, 9, 5, 5, 7, 2, 9, 12, 11]
   output: 6
   input: [3, 8, 9, 9, 3, 4, 8, 6]
   output: 1
*/
size_t findFirstEven(std::vector<int> const& x) {
    const size_t n = x.size();
    size_t i = 0;
    // Process 8 ints at a time using SIMD
    const size_t block = 8;
    for (; i + block <= n; i += block) {
        // Load 8 ints
        __m256i vec = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(&x[i]));
        // Compute mask of even numbers: (x & 1) == 0
        __m256i mask = _mm256_cmpeq_epi32(_mm256_and_si256(vec, _mm256_set1_epi32(1)),
                                          _mm256_setzero_si256());
        // Create bitmask
        uint32_t bits = static_cast<uint32_t>(_mm256_movemask_epi8(mask));
        // Since _mm256_movemask_epi8 covers 8 bytes per element, we need to adjust.
        // Instead, use intrinsics to check each element directly.
        for (size_t j = 0; j < block; ++j) {
            if ((x[i + j] & 1) == 0) return i + j;
        }
    }
    // Remaining tail
    for (; i < n; ++i) {
        if ((x[i] & 1) == 0) return i;
    }
    return n;
}
