#include <omp.h>

/*
 * Multiply the matrix A by the vector x. Store the results in the vector y.
 * A is an MxN matrix stored in row‑major, x has N elements, and y has M elements.
 * Example:
 *   input: A=[[1, -1, 2], [0, -3, 1]] x=[2, 1, 0]
 *   output: y=[1, -3]
 */
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> &y,
                 std::size_t M,
                 std::size_t N)
{
    // Ensure the vectors have the expected sizes (optional safety check)
    // std::size_t aSize = A.size(), xSize = x.size(), ySize = y.size();
    // assert(aSize == M * N && xSize == N && ySize == M);

    constexpr std::size_t BLOCK = 64;          // block size for cache tiling (tuned empirically)
    constexpr std::size_t UNROLL = 4;           // inner loop unroll factor

    const double *Aptr = A.data();
    const double *X = x.data();
    double *Y = y.data();

    // Parallelize over rows with static scheduling
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(M); ++i) {
        double sum = 0.0;
        const double *row = Aptr + i * N;
        std::ptrdiff_t j = 0;

        // Process in blocks for better cache locality
        for (; j + BLOCK <= static_cast<std::ptrdiff_t>(N); j += BLOCK) {
            // Inner block: unrolled loop
            std::ptrdiff_t k = 0;
            for (; k + UNROLL <= static_cast<std::ptrdiff_t>(BLOCK); k += UNROLL) {
                sum += row[j + k]     * X[j + k];
                sum += row[j + k + 1] * X[j + k + 1];
                sum += row[j + k + 2] * X[j + k + 2];
                sum += row[j + k + 3] * X[j + k + 3];
            }
            // Tail of the block (if BLOCK is not multiple of UNROLL)
            for (; k < static_cast<std::ptrdiff_t>(BLOCK); ++k) {
                sum += row[j + k] * X[j + k];
            }
        }

        // Tail rows (if N not multiple of BLOCK)
        for (; j < static_cast<std::ptrdiff_t>(N); ++j) {
            sum += row[j] * X[j];
        }

        Y[i] = sum;
    }
}
