inline double get(double const* M, size_t N, size_t r, size_t c) {
    return M[r * N + c];
}
inline void set(double* M, size_t N, size_t r, size_t c, double v) {
    M[r * N + c] = v;
}

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:

   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N) {
    // Work on a copy to retain the original data
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    // Gaussian elimination with static scheduling and blocking
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N - 1; ++i) {
        double pivot = get(A_copy.data(), N, i, i);
        if (pivot == 0.0) return;   // singular

        double inv_pivot = 1.0 / pivot;

        // Scale pivot row once for efficiency
        for (size_t k = i; k < N; ++k)
            A_copy[i * N + k] *= inv_pivot;
        b_copy[i] *= inv_pivot;

        // Eliminate rows below
        for (size_t j = i + 1; j < N; ++j) {
            double factor = get(A_copy.data(), N, j, i);
            if (factor == 0.0) continue;
            for (size_t k = i; k < N; ++k)
                A_copy[j * N + k] -= factor * A_copy[i * N + k];
            b_copy[j] -= factor * b_copy[i];
        }
    }

    // Back substitution
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j)
            sum += get(A_copy.data(), N, i, j) * x[j];
        x[i] = (b_copy[i] - sum) / get(A_copy.data(), N, i, i);
    }
}
