```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <omp.h>

/*
 * FFT in place, conjugate after transform.
 * Uses an iterative radix‑2 Cooley‑Tukey FFT with
 * pre‑computed twiddle factors.
 * The algorithm runs in O(N log N) with good cache locality
 * and parallelized across the outer ("stage") loop using OpenMP.
 * The final bit‑reversal is also parallelised.
 * No behaviour change relative to the original implementation.
 */

namespace fft_detail {
    // Pre‑compute the twiddle factors for each stage
    inline std::vector<std::vector<std::complex<double>>> precompute_twiddles(unsigned int n) {
        std::vector<std::vector<std::complex<double>>> twiddles;
        unsigned int stage = 1;
        while (stage < n) {
            unsigned int block = stage << 1;
            std::vector<std::complex<double>> vals(stage);
            double theta = -M_PI / stage;                // negative for forward FFT
            std::complex<double> w(1.0, 0.0);
            std::complex<double> wstep(std::cos(theta), std::sin(theta));
            for (unsigned int i = 0; i < stage; ++i) {
                vals[i] = w;
                w *= wstep;
            }
            twiddles.push_back(std::move(vals));
            stage = block;
        }
        return twiddles;
    }

    // Bit‑reversal permutation using a lookup table for 16‑bit halves
    inline void bit_reversal(std::vector<std::complex<double>>& x) {
        const unsigned int N = static_cast<unsigned int>(x.size());
        const unsigned int m  = static_cast<unsigned int>(std::log2(N));

        // 16‑bit lookup table
        static unsigned short rev16[1 << 16];
        static bool init = false;
        if (!init) {
            for (unsigned int i = 0; i < (1 << 16); ++i)
                rev16[i] = ((i & 0xAAAAu) >> 1) | ((i & 0x5555u) << 1);
            rev16[i] = ((rev16[i] & 0xCCCCu) >> 2) | ((rev16[i] & 0x3333u) << 2);
            rev16[i] = ((rev16[i] & 0xF0F0u) >> 4) | ((rev16[i] & 0x0F0Fu) << 4);
            rev16[i] = ((rev16[i] & 0xFF00u) >> 8) | ((rev16[i] & 0x00FFu) << 8);
            init = true;
        }

        #pragma omp parallel for schedule(static)
        for (unsigned int i = 0; i < N; ++i) {
            unsigned int j = i;
            // reverse only the lower m bits
            unsigned int b = ((rev16[j & 0xFFFF] >> (16 - m)) | (rev16[j >> 16] << m)) & ((1U << m) - 1);
            if (b > i) {
                std::swap(x[i], x[b]);
            }
        }
    }
}

inline void fftConjugate(std::vector<std::complex<double>>& x) {
    const unsigned int N = static_cast<unsigned int>(x.size());
    if (N == 0) return;

    // --- 1. Prepare twiddle factors ---------------------------------
    const auto& twiddles = fft_detail::precompute_twiddles(N);

    // --- 2. Bit‑reversal -------------------------------------------------
    fft_detail::bit_reversal(x);

    // --- 3. Iterative FFT -------------------------------------------------
    unsigned int stage = 1;
    for (const auto& W : twiddles) {
        unsigned int block = stage << 1;
        #pragma omp parallel for schedule(static)
        for (unsigned int k = 0; k < N; k += block) {
            for (unsigned int i = k; i < k + stage; ++i) {
                std::complex<double> t = x[i + stage] * W[i & (stage - 1)];
                x[i + stage] = x[i] - t;
                x[i] += t;
            }
        }
        stage = block;
    }

    // --- 4. Conjugate the result ---------------------------------------
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < x.size(); ++i) {
        x[i] = std::conj(x[i]);
    }
}
